// This file is auto-generated to prevent binary file corruption in Git sync.
const fs = require('fs');
const path = require('path');

const RES_DIR = path.join(__dirname, 'android', 'app', 'src', 'main', 'res');
const data = {
  "mipmap-mdpi": {
    "ic_launcher.png": "",
    "ic_launcher_round.png": "",
    "ic_launcher_foreground.png": ""
  },
  "mipmap-hdpi": {
    "ic_launcher.png": "",
    "ic_launcher_round.png": "",
    "ic_launcher_foreground.png": ""
  },
  "mipmap-xhdpi": {
    "ic_launcher.png": "",
    "ic_launcher_round.png": "",
    "ic_launcher_foreground.png": ""
  },
  "mipmap-xxhdpi": {
    "ic_launcher.png": "",
    "ic_launcher_round.png": "",
    "ic_launcher_foreground.png": ""
  },
  "mipmap-xxxhdpi": {
    "ic_launcher.png": "",
    "ic_launcher_round.png": "",
    "ic_launcher_foreground.png": ""
  }
};

console.log('Recreating Android launcher icons from Base64...');

for (const [dir, files] of Object.entries(data)) {
  const dirPath = path.join(RES_DIR, dir);
  if (!fs.existsSync(dirPath)) {
    fs.mkdirSync(dirPath, { recursive: true });
  }
  for (const [file, base64] of Object.entries(files)) {
    const filePath = path.join(dirPath, file);
    fs.writeFileSync(filePath, Buffer.from(base64, 'base64'));
    console.log('Recreated:', filePath);
  }
}

console.log('All Android launcher icons successfully recreated!');
